components.shader:
precision mediump float;
uniform sampler2D tSource;
uniform float uTime;
varying vec2 vUv;
void main() {
  vec2 center = vec2(0.5);
  vec2 p = vUv - center;
  float r = length(p);
  // Mode 22: phonic rings - quantized ring zoom
  float rings = floor(r * 20.0);
  float scale1 = 0.95 - rings * 0.008;
  float turn1 = 0.015 + 0.01*sin(uTime*0.23);
  float cs = cos(turn1);
  float sn = sin(turn1);
  vec2 rotated = vec2(p.x*cs - p.y*sn, p.x*sn + p.y*cs);
  vec2 uv = rotated * (1.0/scale1) + center;
  uv = clamp(uv, 0.0, 1.0);
  gl_FragColor = texture2D(tSource, uv) * 0.988;
}
